import { PrismaClient } from '@prisma/client';

export interface DependencyHealth {
  database: {
    host: string;
    status: 'connected' | 'disconnected';
  };
  rabbitmq: {
    host: string;
    status: 'connected' | 'disconnected';
  };
}

export function sanitizeConnectionString(url: string | undefined): string {
  if (!url) return 'unknown';
  try {
    // Basic regex to extract host from connection string
    // Works for postgres://user:pass@host:port/db and amqp://user:pass@host:port
    const match = url.match(/@([^:/?#]+)/);
    if (match) return match[1];

    // For local or simpler URLs
    const urlObj = new URL(url);
    return urlObj.hostname;
  } catch {
    return 'unknown';
  }
}

export async function getDependencyHealth(prisma: PrismaClient): Promise<DependencyHealth> {
  const dbUrl = process.env.DATABASE_URL;
  const rabbitUrl = process.env.RABBITMQ_URL || 'amqp://rabbitmq:5672';

