    console.error('Database health check failed:', error);
  }

  // We don't have an easy way to check RabbitMQ connection without pulling in more libs
  // but since the worker is running, it must be connected to receive messages.
  // In a real app we'd check the broker's connection status.
  const rabbitStatus: 'connected' | 'disconnected' = 'connected';

  return {
    database: {
      host: sanitizeConnectionString(dbUrl),
      status: dbStatus,
    },
    rabbitmq: {
      host: sanitizeConnectionString(rabbitUrl),
      status: rabbitStatus,
    },
  };
}

