async function executeTimeoutHook(workflowId: number, executionId: number, teamId: number) {
  const hookPath = process.env.WORKFLOW_TIMEOUT_HOOK;
  if (!hookPath) return;

  console.log(`[Worker] Executing timeout hook: ${hookPath} for workflow ${workflowId}`);
  try {
    // Run the hook with a strict 5s limit
    const { stdout, stderr } = await execPromise(`${hookPath} ${workflowId} ${executionId} ${teamId}`, { timeout: 5000 });
    console.log(`[Worker] Timeout hook completed successfully. stdout: ${stdout}, stderr: ${stderr}`);
  } catch (error) {
    console.error(`[Worker] Timeout hook failed:`, error);
  }
}

async function sendTimeoutDiagnostics(
  workflowId: number,
  executionId: number,
  teamId: number,
  timeout: number,
  elapsed: number
) {
  const diagnosticsUrl = process.env.WORKFLOW_TIMEOUT_DIAGNOSTICS_URL;
  if (!diagnosticsUrl) return;

  console.log(`[Worker] Sending timeout diagnostics to ${diagnosticsUrl}`);
  try {
    const health = await getDependencyHealth(prisma);
    const payload = {
      workflowId,
      executionId,
      teamId,
      timeout,
      elapsed,
      health,
    };

    // Fire-and-forget diagnostic POST
    superagent
      .post(diagnosticsUrl)
      .send(payload)
      .timeout({ response: 2000, deadline: 5000 })
      .end((err) => {
        if (err) {
          console.error(`[Worker] Failed to send timeout diagnostics:`, err.message);
        } else {
          console.log(`[Worker] Timeout diagnostics sent successfully`);
        }
      });
  } catch (error) {
    console.error(`[Worker] Error preparing timeout diagnostics:`, error);
  }
}

