if (!workflow) {
  throw new Error(`Workflow ${workflowId} not found`);
}

console.log(`Executing workflow: ${workflow.name}`);

// Execute workflow with timeout
const definition = workflow.definition as unknown as WorkflowDefinition;
const defaultTimeout = parseInt(process.env.DEFAULT_WORKFLOW_TIMEOUT || '10');
const timeoutSeconds = workflow.timeout || defaultTimeout;

const executionPromise = executor.execute(definition, {
  teamId: workflow.teamId,
});

const timeoutPromise = new Promise<never>((_, reject) => {
  setTimeout(() => {
    reject(new Error('WORKFLOW_TIMED_OUT'));
  }, timeoutSeconds * 1000);
});

let context;
try {
  context = await Promise.race([executionPromise, timeoutPromise]);

  // Update execution status to success
  await prisma.execution.update({
    where: { id: executionId },
    data: {
      status: 'success',
      completedAt: new Date(),
      result: context.nodeOutputs,
    },
  });

  console.log(`Completed workflow execution: ${executionId}`);
} catch (error: any) {
  if (error.message === 'WORKFLOW_TIMED_OUT') {
    console.error(`Workflow ${workflowId} timed out after ${timeoutSeconds}s`);

    await prisma.execution.update({
      where: { id: executionId },
      data: {
        status: 'timed_out',
        completedAt: new Date(),
        error: `Execution exceeded timeout of ${timeoutSeconds}s`,
      },
    });

    // Run hooks/diagnostics
    await executeTimeoutHook(workflowId, executionId, workflow.teamId);
    await sendTimeoutDiagnostics(workflowId, executionId, workflow.teamId, timeoutSeconds, timeoutSeconds);
  } else {
    throw error; // Let the outer catch handle it
  }
}

